const bindingFunc = async (
    text: string,
    userToSend: string,
    telegramInstance: string,
    oneTimeKeyboard: boolean,
    resizeKeyboard: boolean,
    userListWithChatID: UserListWithChatId[],
    parseMode?: boolean,
): Promise<void> => {
    let value;

    try {
        const substring = decomposeText(text, 'binding:', '}').substring;
        const arrayOfItems = substring.replace('binding:{', '').replace('}', '').split(';');
        const bindingObject: BindingObject = {
            values: {},
        };

        for (let item of arrayOfItems) {
            if (!item.includes('?')) {
                const key = item.split(':')[0];
                const id = item.split(':')[1];

                const result = await adapter.getForeignStateAsync(id);
                if (result) {
                    bindingObject.values[key] = result.val?.toString() || '';
                }
            } else {
                Object.keys(bindingObject.values).forEach(function (key) {
                    item = item.replace(key, bindingObject.values[key]);
                });

                value = eval(item);
            }
        }
        await sendToTelegram({
            userToSend,
            textToSend: value,
            instanceTelegram: telegramInstance,
            resizeKeyboard,
            oneTimeKeyboard,
            userListWithChatID,
            parseMode,
        });
    } catch (e: any) {
        errorLogger('Error Binding function: ', e, adapter);
    }
};

function editArrayButtons(val: EditArrayButtons[]): GeneratedNavMenu[] | null {
    const newVal: GeneratedNavMenu[] = [];
    try {
        val.forEach(element => {
            let value = '';
            if (typeof element.value === 'string') {
                value = checkOneLineValue(element.value);
            }
            let array: string[] | string[][] = [];
            if (value.indexOf(config.rowSplitter) != -1) {
                array = value.split(config.rowSplitter);
            }

            if (array.length > 1) {
                array.forEach(function (element, index: number) {
                    if (typeof element === 'string') {
                        let navArray = element.split(',');
                        navArray = navArray.map(item => item.trim());
                        array[index] = navArray;
                    }
                });
            } else if (typeof element.value === 'string') {
                array = element.value.split(',');
                array.forEach(function (element, index: number) {
                    array[index] = [element.trim()];
                });
            }

            newVal.push({ call: element.call, text: element.text, parseMode: element.parseMode, nav: array });
        });

        return newVal;
    } catch (err: any) {
        errorLogger('Error EditArray:', err, adapter);
        return null;
    }
}

const idBySelector = async ({
    selector,
    text,
    userToSend,
    newline,
    telegramInstance,
    oneTimeKeyboard,
    resizeKeyboard,
    userListWithChatID,
}: {
    selector: string;
    text: string;
    userToSend: string;
    newline: Newline;
    telegramInstance: string;
    oneTimeKeyboard: boolean;
    resizeKeyboard: boolean;
    userListWithChatID: UserListWithChatId[];
}): Promise<void> => {
    let text2Send = '';
    try {
        if (!selector.includes('functions')) {
            return;
        }

        const functions = selector.replace('functions=', '');
        let enums: string[] | undefined = [];
        const result = await adapter.getEnumsAsync();

        if (!result || !result['enum.functions'][`enum.functions.${functions}`]) {
            return;
        }
        enums = result['enum.functions'][`enum.functions.${functions}`].common.members;
        if (!enums) {
            return;
        }
        const promises = enums.map(async (id: string) => {
            const value = await adapter.getForeignStateAsync(id);
            if (value && value.val !== undefined && value.val !== null) {
                let newText = text;
                let res;

                if (text.includes('{common.name}')) {
                    res = await adapter.getForeignObjectAsync(id);
                    adapter.log.debug(`Name ${JSON.stringify(res?.common.name)}`);

                    if (res && res.common.name) {
                        newText = newText.replace('{common.name}', res.common.name as string);
                    }
                }
                if (text.includes('&amp;&amp;')) {
                    text2Send += newText.replace('&amp;&amp;', value.val as string);
                } else if (text.includes('&&')) {
                    text2Send += newText.replace('&&', value.val as string);
                } else {
                    text2Send += newText;
                    text2Send += ` ${value.val}`;
                }
            }
            if (newline === 'true') {
                text2Send += ' \n';
            } else {
                text2Send += ' ';
            }
            adapter.log.debug(`text2send ${JSON.stringify(text2Send)}`);
        });
        Promise.all(promises)
            .then(() => {
                sendToTelegram({
                    userToSend,
                    textToSend: text2Send,
                    instanceTelegram: telegramInstance,
                    resizeKeyboard,
                    oneTimeKeyboard,
                    userListWithChatID,
                }).catch(e => {
                    errorLogger('Error SendToTelegram:', e, adapter);
                });

                adapter.log.debug(`TextToSend: ${text2Send}`);
                adapter.log.debug(`UserToSend: ${userToSend}`);
            })
            .catch(e => {
                errorLogger('Error Promise:', e, adapter);
            });
    } catch (error: any) {
        errorLogger('Error idBySelector: ', error, adapter);
    }
};

function generateNewObjectStructure(val?: GeneratedNavMenu[] | null): NewObjectNavStructure | null {
    try {
        if (!val) {
            return null;
        }
        const obj: NewObjectNavStructure = {};
        val.forEach(function ({ nav, text, parseMode, call }) {
            obj[call] = {
                nav,
                text,
                parseMode: isTruthy(parseMode),
            };
        });
        return obj;
    } catch (err: any) {
        errorLogger('Error GenerateNewObjectStructure:', err, adapter);
        return null;
    }
}

function generateActions(
    action: Actions,
    userObject: NewObjectNavStructure,
): { obj: NewObjectNavStructure; ids: string[] } | undefined {
    try {
        const arrayOfEntries: GenerateActionsArrayOfEntries[] = [
            {
                objName: 'echarts',
                name: 'echarts',
                loop: 'preset',
                elements: [
                    { name: 'preset' },
                    { name: 'echartInstance' },
                    { name: 'background' },
                    { name: 'theme' },
                    { name: 'filename' },
                ],
            },
            {
                objName: 'loc',
                name: 'location',
                loop: 'latitude',
                elements: [{ name: 'latitude' }, { name: 'longitude' }, { name: 'parseMode', key: 0 }],
            },
            {
                objName: 'pic',
                name: 'sendPic',
                loop: 'IDs',
                elements: [
                    { name: 'id', value: 'IDs' },
                    { name: 'fileName' },
                    { name: 'delay', value: 'picSendDelay' },
                ],
            },
            {
                objName: 'get',
                name: 'getData',
                loop: 'IDs',
                elements: [
                    { name: 'id', value: 'IDs' },
                    { name: 'text', type: 'text' },
                    { name: 'newline', value: 'newline_checkbox' },
                    { name: 'parseMode', key: 0 },
                ],
            },
            {
                objName: 'httpRequest',
                name: 'httpRequest',
                loop: 'url',
                elements: [{ name: 'url' }, { name: 'user' }, { name: 'password' }, { name: 'filename' }],
            },
        ];

        const listOfSetStateIds: string[] = [];
        action.set.forEach(function (element, key) {
            if (key == 0) {
                userObject[element.trigger[0]] = { switch: [] };
            }
            userObject[element.trigger[0]] = { switch: [] };

            element.IDs.forEach(function (id: string, index: number) {
                listOfSetStateIds.push(id);
                const toggle = element.switch_checkbox[index] === 'true';
                let value;

                if (element.values[index] === 'true' || element.values[index] === 'false') {
                    value = element.values[index] === 'true';
                } else {
                    value = element.values[index];
                }
                const newObj: Switch = {
                    id: element.IDs[index],
                    value: value.toString(),
                    toggle: toggle,
                    confirm: element.confirm[index],
                    returnText: element.returnText[index],
                    ack: element.ack ? element.ack[index] : 'false',
                    parseMode: isTruthy(element.parseMode[0]),
                };
                if (userObject[element.trigger[0]] && userObject[element.trigger[0]]?.switch) {
                    userObject[element.trigger[0]].switch!.push(newObj);
                }
            });
        });

        arrayOfEntries.forEach(item => {
            if (action[item.objName as keyof Actions]) {
                action[item.objName as keyof Actions].forEach(function (element, index: number) {
                    userObject[element.trigger[0]] = { [item.name]: [] };
                    if (index == 0) {
                        userObject[element.trigger[0]] = { [item.name as keyof UserObjectActions]: [] };
                    }

                    (element[item.loop as keyof typeof element] as string[]).forEach(function (
                        id: string,
                        key: number,
                    ) {
                        const newObj: GenerateActionsNewObject = {};
                        item.elements.forEach(elementItem => {
                            const name = elementItem.name;
                            const value = elementItem.value ? elementItem.value : elementItem.name;
                            const newKey = elementItem.key ? elementItem.key : key;
                            let val: string | boolean;

                            if (!element[value as keyof typeof element]) {
                                val = false;
                            } else {
                                val = element[value as keyof typeof element][newKey] || 'false';
                            }

                            if (elementItem.type == 'text' && typeof val === 'string') {
                                newObj[name as keyof GenerateActionsNewObject] = val.replace(/&amp;/g, '&') as any;
                            } else {
                                newObj[name as keyof GenerateActionsNewObject] = val as any;
                            }
                        });
                        if (item.name && typeof item.name === 'string') {
                            userObject[element.trigger as string][item?.name as keyof Part].push(newObj);
                        }
                    });
                });
            }
        });

        return { obj: userObject, ids: listOfSetStateIds };
    } catch (err: any) {
        errorLogger('Error generateActions:', err, adapter);
    }
}

const exchangePlaceholderWithValue = (textToSend: string, val: PrimitiveType): string => {
    let searchString = '';
    if (textToSend.includes('&&')) {
        searchString = '&&';
    } else if (textToSend.includes('&amp;&amp;')) {
        searchString = '&amp;&amp;';
    }
    searchString !== '' && textToSend.toString().indexOf(searchString) != -1
        ? (textToSend = textToSend.replace(searchString, val.toString()))
        : (textToSend += ` ${val}`);

    return textToSend;
};

const adjustValueType = (value: keyof NewObjectNavStructure, valueType: string): boolean | string | number => {
    if (valueType == 'number') {
        if (!parseFloat(value)) {
            adapter.log.error(`Error: Value is not a number: ${value}`);
            return false;
        }
        return parseFloat(value);
    }
    if (valueType == 'boolean') {
        if (value == 'true') {
            return true;
        }
        adapter.log.error(`Error: Value is not a boolean: ${value}`);
        return false;
    }
    return value;
};

const checkEvent = async (
    dataObject: DataObject,
    id: string,
    state: ioBroker.State,
    menuData: MenuData,
    userListWithChatID: UserListWithChatId[],
    instanceTelegram: string,
    resizeKeyboard: boolean,
    oneTimeKeyboard: boolean,
    usersInGroup: UserInGroup,
): Promise<boolean> => {
    const menuArray: string[] = [];
    let ok = false;
    let calledNav = '';
    Object.keys(dataObject.action).forEach(menu => {
        if (dataObject.action[menu] && dataObject.action[menu].events) {
            dataObject.action[menu].events.forEach(event => {
                if (event.ID[0] == id && event.ack[0] == state.ack.toString()) {
                    if ((state.val == true || state.val == 'true') && event.condition == 'true') {
                        ok = true;
                        menuArray.push(menu);
                        calledNav = event.menu[0];
                    } else if ((state.val == false || state.val == 'false') && event.condition[0] == 'false') {
                        ok = true;
                        menuArray.push(menu);
                        calledNav = event.menu[0];
                    } else if (typeof state.val == 'number' && state.val == parseInt(event.condition[0])) {
                        ok = true;
                        menuArray.push(menu);
                        calledNav = event.menu[0];
                    } else if (state.val == event.condition[0]) {
                        ok = true;
                        menuArray.push(menu);
                        calledNav = event.menu[0];
                    }
                }
            });
        }
    });
    if (ok) {
        if (menuArray.length >= 1) {
            for (const menu of menuArray) {
                if (usersInGroup[menu] && menuData.data[menu][calledNav as keyof DataObject]) {
                    for (const user of usersInGroup[menu]) {
                        const part = menuData.data[menu][calledNav as keyof DataObject];
                        const menus = Object.keys(menuData.data);
                        if (part.nav) {
                            backMenuFunc(calledNav, part.nav, user);
                        }
                        if (part?.nav && part?.nav[0][0].includes('menu:')) {
                            await callSubMenu(
                                JSON.stringify(part?.nav[0]),
                                menuData,
                                user,
                                instanceTelegram,
                                resizeKeyboard,
                                oneTimeKeyboard,
                                userListWithChatID,
                                part,
                                menuData.data,
                                menus,
                                null,
                                part.nav,
                            );
                        } else {
                            await sendNav(
                                part,
                                user,
                                instanceTelegram,
                                userListWithChatID,
                                resizeKeyboard,
                                oneTimeKeyboard,
                            );
                        }
                    }
                }
            }
        }
    }

    return ok;
};

const getUserToSendFromUserListWithChatID = (
    userListWithChatID: UserListWithChatId[],
    chatID: string,
): string | null => {
    let userToSend: string | null = null;

    for (const element of userListWithChatID) {
        if (element.chatID == chatID) {
            userToSend = element.name;
            break;
        }
    }

    return userToSend;
};

